package policy

import (
	"context"
	"encoding/json"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
	"github.com/cilium/cilium/pkg/policy/api"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	mu       lock.Mutex
	logLevel logrus.Level
	logger   logrus.FieldLogger
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the given log level
// and logger instance.
func NewPolicyAuditLogger(logger logrus.FieldLogger, level logrus.Level) *PolicyAuditLogger {
	if logger == nil {
		logger = log
	}
	return &PolicyAuditLogger{
		logLevel: level,
		logger:   logger,
	}
}

// LogDecision logs a policy decision with identity, policy, verdict, and reason.
// This method is thread-safe.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict api.Decision, reason string) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	if !pal.shouldLog() {
		return
	}

	fields := logrus.Fields{
		logfields.Identity:     identity,
		"policyName":           policy,
		"verdict":              verdict.String(),
		"reason":               reason,
	}

	pal.logWithFields(fields, "Policy decision logged")
}

// LogEvaluation logs a policy evaluation result with context, policy key, selector cache,
// and evaluation result. This method is thread-safe.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result interface{}) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	if !pal.shouldLog() {
		return
	}

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
	}

	// Add result information if available
	if result != nil {
		// Convert result to JSON for structured logging
		if jsonBytes, err := json.Marshal(result); err == nil {
			fields["evaluationResult"] = string(jsonBytes)
		} else {
			fields["evaluationResult"] = result
		}
	}

	// Add selector cache info if available
	if selectorCache != nil {
		fields["selectorCacheActive"] = true
	}

	pal.logWithFields(fields, "Policy evaluation logged")
}

// shouldLog checks if the current log level allows logging at the logger's configured level
func (pal *PolicyAuditLogger) shouldLog() bool {
	// Get the current logger's level and compare with our configured level
	if entry, ok := pal.logger.(*logrus.Entry); ok {
		return entry.Logger.IsLevelEnabled(pal.logLevel)
	}
	if logger, ok := pal.logger.(*logrus.Logger); ok {
		return logger.IsLevelEnabled(pal.logLevel)
	}
	// If we can't determine the level, allow logging
	return true
}

// logWithFields logs a message with the given fields at the configured log level
func (pal *PolicyAuditLogger) logWithFields(fields logrus.Fields, message string) {
	entry := pal.logger.WithFields(fields)

	switch pal.logLevel {
	case logrus.DebugLevel:
		entry.Debug(message)
	case logrus.InfoLevel:
		entry.Info(message)
	case logrus.WarnLevel:
		entry.Warn(message)
	case logrus.ErrorLevel:
		entry.Error(message)
	default:
		entry.Debug(message)
	}
}

// SetLogLevel updates the log level for this audit logger
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	pal.logLevel = level
}

// GetLogLevel returns the current log level
func (pal *PolicyAuditLogger) GetLogLevel() logrus.Level {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	return pal.logLevel
}

// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/policy/api"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := logrus.New()
	fieldLogger := logger.WithField("test", "value")

	// Test with custom logger
	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)
	require.Equal(t, logrus.InfoLevel, auditor.GetLogLevel())

	// Test with nil logger (should use default)
	auditor2 := NewPolicyAuditLogger(nil, logrus.DebugLevel)
	require.NotNil(t, auditor2)
	require.Equal(t, logrus.DebugLevel, auditor2.GetLogLevel())
}

func TestLogDecision(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "audit")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)

	// Test logging allowed decision
	testID := identity.NumericIdentity(1001)
	auditor.LogDecision(testID, "test-policy", api.Allowed, "matched ingress rule")
	// No panic should occur

	// Test logging denied decision
	auditor.LogDecision(testID, "deny-policy", api.Denied, "matched deny rule")
	// No panic should occur

	// Test logging undecided
	auditor.LogDecision(testID, "undecided-policy", api.Undecided, "no matching rules")
	// No panic should occur
}

func TestLogEvaluation(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "audit")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.DebugLevel)
	require.NotNil(t, auditor)

	ctx := context.Background()

	// Test with nil result
	auditor.LogEvaluation(ctx, "policy-key-1", nil, nil)
	// No panic should occur

	// Test with map result
	result := map[string]interface{}{
		"matched":    true,
		"ruleCount":  3,
		"selectores": []string{"app=web"},
	}
	auditor.LogEvaluation(ctx, "policy-key-2", nil, result)
	// No panic should occur

	// Test with string result
	auditor.LogEvaluation(ctx, "policy-key-3", nil, "test result")
	// No panic should occur
}

func TestLogDecisionThreadSafety(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "thread")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)

	// Run concurrent logging
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(id int) {
			testID := identity.NumericIdentity(1000 + id)
			auditor.LogDecision(testID, "thread-test", api.Allowed, "concurrent test")
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		<-done
	}
	// No panic should occur
}

func TestLogEvaluationThreadSafety(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "thread")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.DebugLevel)
	require.NotNil(t, auditor)

	ctx := context.Background()

	// Run concurrent evaluation logging
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(id int) {
			result := map[string]int{"evaluationID": id}
			auditor.LogEvaluation(ctx, "key-"+string(rune(id)), nil, result)
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		<-done
	}
	// No panic should occur
}

func TestSetAndGetLogLevel(t *testing.T) {
	logger := logrus.New()
	fieldLogger := logger.WithField("test", "level")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.Equal(t, logrus.InfoLevel, auditor.GetLogLevel())

	// Change log level
	auditor.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, auditor.GetLogLevel())

	auditor.SetLogLevel(logrus.WarnLevel)
	require.Equal(t, logrus.WarnLevel, auditor.GetLogLevel())

	auditor.SetLogLevel(logrus.ErrorLevel)
	require.Equal(t, logrus.ErrorLevel, auditor.GetLogLevel())
}

func TestLogDecisionWithDifferentVerdicts(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "verdicts")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)

	testID := identity.NumericIdentity(2001)

	// Test all verdict types
	verdicts := []api.Decision{
		api.Allowed,
		api.Denied,
		api.Undecided,
	}

	for _, verdict := range verdicts {
		auditor.LogDecision(testID, "test-policy", verdict, "testing verdict: "+verdict.String())
		// Verify verdict string representation works
		require.NotEmpty(t, verdict.String())
	}
}

func TestLogEvaluationWithComplexResult(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "complex")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.DebugLevel)
	require.NotNil(t, auditor)

	ctx := context.Background()

	// Test with complex nested structure
	complexResult := map[string]interface{}{
		"policy": map[string]interface{}{
			"name":     "allow-all",
			"revision": 42,
		},
		"selectors": []map[string]string{
			{"key": "app", "value": "web"},
			{"key": "env", "value": "prod"},
		},
		"allowed": true,
	}

	auditor.LogEvaluation(ctx, "complex-policy-key", nil, complexResult)
	// No panic should occur and JSON serialization should work
}

func TestLogDecisionWithEmptyReason(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "empty")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)

	testID := identity.NumericIdentity(3001)

	// Test with empty reason
	auditor.LogDecision(testID, "test-policy", api.Allowed, "")
	// No panic should occur even with empty reason
}

